import { Lock, MessageSquare, ShieldCheck, Sparkles } from "lucide-react";
import type { FC, ReactNode } from "react";

import { cn } from "@/shared/lib/ui/cn";
import { Header } from "@/widgets/header";

const FEATURES = [
  { Icon: MessageSquare, label: "100% Discreet Transactions" },
  { Icon: Sparkles, label: "AI-Powered Valuation" },
  { Icon: ShieldCheck, label: "Fully-Insured Shipping" },
  { Icon: Lock, label: "Secure Storage" },
];

type AuthLayoutProps = {
  children: ReactNode;
};

export const AuthLayout: FC<AuthLayoutProps> = ({ children }) => (
  <div className="new-design mt-[61px] flex min-h-screen flex-col bg-[#F5F3EF] max-lg:mt-[48px]">
    <Header />

    <div className="flex flex-1 items-stretch">
      {/* Left: Marketing Content */}
      <div className="hidden flex-1 flex-col justify-between p-10 lg:flex">
        {/* UAE Badge */}
        <div className="flex w-fit items-center gap-3 rounded-full border border-[#A8A29E] px-4 py-3">
          <span aria-hidden>🇦🇪</span>
          <span className="font-new-sans text-[#44403C] text-base leading-[150%] tracking-[-0.01em]">
            Now available in UAE
          </span>
        </div>

        {/* Hero Headline */}
        <p
          className="max-w-[700px] font-new-serif text-[#000944] text-[72px] leading-[110%]"
          style={{ fontWeight: 200 }}
        >
          Your secured platform for selling and buyback luxury items.
        </p>

        {/* Feature Callouts */}
        <div className="flex max-w-[660px] flex-wrap gap-x-10">
          {FEATURES.map(({ Icon, label }, i) => (
            <div
              className={cn(
                "flex w-[299px] items-center gap-2 py-5",
                i < 2 && "border-[#D6D3D1] border-b"
              )}
              key={label}
            >
              <Icon
                className="shrink-0 text-[#44403C]"
                size={32}
                strokeWidth={1.25}
              />
              <span className="font-new-sans text-[#44403C] text-base leading-[150%] tracking-[-0.01em]">
                {label}
              </span>
            </div>
          ))}
        </div>
      </div>

      {/* Right: Form Card */}
      <div className="flex w-full items-center justify-center px-6 py-8 lg:w-[660px] lg:shrink-0 lg:px-[120px]">
        <div className="w-full max-w-[420px] rounded-2xl border border-[#D6D3D1] bg-[#F5F3EF] pt-8 pb-6 shadow-[0px_20px_28px_rgba(0,0,0,0.05)] [padding-inline:24px]">
          {children}
        </div>
      </div>
    </div>
  </div>
);

"use client";

import { zodResolver } from "@hookform/resolvers/zod";
import Link from "next/link";
import { useRouter } from "next/navigation";
import { useForm } from "react-hook-form";
import { z } from "zod";

import { sendOtp } from "@/entities/auth/api/services";
import {
  useCheckEmailExists,
  useCheckPhoneExists,
} from "@/shared/api/query-hooks/use-auth-checks";
import { APP_ROUTES } from "@/shared/config/app-routes";
import { USER_ROLES } from "@/shared/constants";
import { authStorage } from "@/shared/lib/storage/auth-storage";
import { OtpType } from "@/shared/types/auth.types";
import { Checkbox } from "@/shared/ui/checkbox";
import { Form } from "@/shared/ui/form/form";
import { FormControl } from "@/shared/ui/form/form-control";
import { FormField } from "@/shared/ui/form/form-field";
import { FormItem } from "@/shared/ui/form/form-item";
import { FormLabel } from "@/shared/ui/form/form-label";
import { FormMessage } from "@/shared/ui/form/form-message";
import { Input } from "@/shared/ui/input";
import { toast } from "@/shared/ui/notification";
import { PhoneInput } from "@/shared/ui/phone-input";
import { Button } from "@/shared/ui/shadcn/button";

const signupSchema = z.object({
  firstName: z.string().min(2, "First name must be at least 2 characters"),
  lastName: z.string().min(1, "Last name is required"),
  patronymic: z.string().optional(),
  email: z.string().email("Please enter a valid email"),
  phone: z.string().min(10, "Phone number must be at least 10 digits"),
  uaeResident: z.boolean(),
});

type SignupFormData = z.infer<typeof signupSchema>;

function GoogleIcon() {
  return (
    <svg
      aria-hidden="true"
      width="20"
      height="20"
      viewBox="0 0 20 20"
      fill="none"
      xmlns="http://www.w3.org/2000/svg"
    >
      <path
        d="M19.6 10.23c0-.68-.06-1.36-.18-2H10v3.79h5.37a4.61 4.61 0 0 1-1.99 3.01v2.5h3.22c1.88-1.73 2.96-4.28 2.96-7.3z"
        fill="#4285F4"
      />
      <path
        d="M10 20c2.7 0 4.96-.9 6.61-2.43l-3.22-2.5c-.9.6-2.04.96-3.39.96-2.61 0-4.82-1.76-5.61-4.13H1.06v2.57A9.99 9.99 0 0 0 10 20z"
        fill="#34A853"
      />
      <path
        d="M4.39 11.9A5.9 5.9 0 0 1 4.08 10c0-.66.12-1.3.31-1.9V5.53H1.06A9.99 9.99 0 0 0 0 10c0 1.61.38 3.13 1.06 4.47l3.33-2.57z"
        fill="#FBBC05"
      />
      <path
        d="M10 3.97c1.47 0 2.8.51 3.84 1.5l2.87-2.87C15 .9 12.71 0 10 0A9.99 9.99 0 0 0 1.06 5.53L4.39 8.1C5.18 5.73 7.39 3.97 10 3.97z"
        fill="#EA4335"
      />
    </svg>
  );
}

function AppleIcon() {
  return (
    <svg
      aria-hidden="true"
      width="20"
      height="20"
      viewBox="0 0 814 1000"
      fill="none"
      xmlns="http://www.w3.org/2000/svg"
    >
      <path
        d="M788.1 340.9c-5.8 4.5-108.2 62.2-108.2 190.5 0 148.4 130.3 200.9 134.2 202.2-.6 3.2-20.7 71.9-68.7 141.9-42.8 61.6-87.5 123.1-155.5 123.1s-85.5-39.5-164-39.5c-76 0-103.7 40.8-165.9 40.8s-105.5-57.9-168.5-127.6C46.7 696 0 556.4 0 422.9c0-167.9 109.4-256.9 216.7-256.9 70.1 0 128.6 46.3 172.3 46.3 43.4 0 111.1-49 191.5-49 30.2 0 108.2 2.6 162.4 76.5zm-205.5-165.3c33.5-39.5 56.4-94.2 56.4-148.9 0-7.7-.6-15.5-1.9-22.5-53.5 2-116.8 35.7-154.3 80.1-30.5 35.7-58.5 90.4-58.5 145.8 0 8.4 1.3 16.7 1.9 19.3 3.2.6 8.4 1.3 13.6 1.3 48.1 0 109.5-32.3 143.8-75.1z"
        fill="#44403C"
      />
    </svg>
  );
}

function UaePassIcon() {
  return (
    <svg
      aria-hidden="true"
      width="21"
      height="20"
      viewBox="0 0 21 20"
      fill="none"
      xmlns="http://www.w3.org/2000/svg"
    >
      <rect x="0.5" width="20" height="20" rx="3" fill="#00AEEF" />
      <path
        d="M5.5 10h10M7.5 6.5h6M7.5 13.5h6"
        stroke="white"
        strokeWidth="1.5"
        strokeLinecap="round"
      />
    </svg>
  );
}

const SOCIAL_BUTTONS = [
  { key: "google", Icon: GoogleIcon, label: "Google" },
  { key: "apple", Icon: AppleIcon, label: "Apple" },
  { key: "uaepass", Icon: UaePassIcon, label: "UAE Pass" },
];

export function SignupForm() {
  const router = useRouter();

  const checkEmailExists = useCheckEmailExists();
  const checkPhoneExists = useCheckPhoneExists();

  const form = useForm<SignupFormData>({
    resolver: zodResolver(signupSchema),
    defaultValues: {
      firstName: "",
      lastName: "",
      patronymic: "",
      email: "",
      phone: "",
      uaeResident: false,
    },
  });

  const { isSubmitting } = form.formState;

  const onSubmit = async (data: SignupFormData) => {
    try {
      const [emailCheckResult, phoneCheckResult] = await Promise.all([
        checkEmailExists.mutateAsync(data.email),
        checkPhoneExists.mutateAsync(data.phone),
      ]);

      let hasErrors = false;

      if (emailCheckResult.exists) {
        form.setError("email", {
          type: "manual",
          message:
            "This email is already registered. Please use a different email or sign in.",
        });
        hasErrors = true;
      }

      if (phoneCheckResult.exists) {
        form.setError("phone", {
          type: "manual",
          message:
            "This phone number is already registered. Please use a different number or sign in.",
        });
        hasErrors = true;
      }

      if (hasErrors) {
        return;
      }

      const otpResponse = await sendOtp({
        email: data.email,
        phone: data.phone,
        type: OtpType.SIGN_UP,
      });

      authStorage.signup.set({
        email: data.email,
        phone: data.phone,
        firstName: data.firstName,
        lastName: data.lastName,
        patronymic: data.patronymic || undefined,
        role: USER_ROLES.SELLER,
        referralCode: undefined,
        devEmailOtp: otpResponse.otp,
        devPhoneOtp: otpResponse.otp,
      });

      if (otpResponse.otp) {
        toast.success("OTP Generated", {
          description: "Check the verification page for your OTP codes",
        });
      } else {
        toast.success("OTP Sent", {
          description: "Please check your email and phone for OTP codes",
        });
      }

      router.push(APP_ROUTES.AUTH.VERIFY_OTP);
    } catch {
      toast.error("Failed to Send OTP", {
        description: "Please try again later",
      });
    }
  };

  return (
    <div className="flex w-full flex-col gap-8">
      {/* Header */}
      <div className="flex flex-col gap-2">
        <h1 className="font-light font-new-serif text-2xl text-[#44403C] leading-[120%]">
          Join LuxFlow
        </h1>
        <p className="font-new-sans text-[#44403C] text-base leading-[150%] tracking-[-0.01em]">
          Get valuations, manage your offers, and unlock liquidity for your
          luxury items.
        </p>
      </div>

      {/* Social Buttons */}
      <div className="flex gap-2">
        {SOCIAL_BUTTONS.map(({ key, Icon, label }) => (
          <button
            key={key}
            type="button"
            disabled
            className="flex flex-1 cursor-not-allowed items-center justify-center gap-2 rounded-[4px] border border-[#A8A29E] bg-[#F5F3EF] px-4 py-3 font-medium font-new-sans text-[#44403C] text-sm tracking-[-0.01em] opacity-70"
          >
            <Icon />
            <span>{label}</span>
          </button>
        ))}
      </div>

      {/* Form Section */}
      <div className="flex flex-col gap-5">
        {/* OR Divider */}
        <div className="flex items-center gap-4">
          <div className="flex-1 border-[#D6D3D1] border-t" />
          <span className="font-bold font-new-sans text-[#A8A29E] text-sm tracking-[-0.01em]">
            OR
          </span>
          <div className="flex-1 border-[#D6D3D1] border-t" />
        </div>

        <Form {...form}>
          <form
            onSubmit={form.handleSubmit(onSubmit)}
            className="flex flex-col gap-5"
          >
            <div className="flex flex-col gap-2">
              {/* First Name + Last Name */}
              <div className="grid grid-cols-2 gap-2">
                <FormField
                  control={form.control}
                  name="firstName"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel className="font-new-sans font-normal text-[#44403C] text-sm leading-[130%]">
                        First Name
                      </FormLabel>
                      <FormControl>
                        <Input
                          placeholder="Enter your first name"
                          className="h-12 rounded-[4px] border-[#A8A29E] bg-[#F5F3EF] px-3 font-new-sans text-[#44403C] text-sm placeholder:text-[#A8A29E]"
                          {...field}
                        />
                      </FormControl>
                      <FormMessage />
                    </FormItem>
                  )}
                />
                <FormField
                  control={form.control}
                  name="lastName"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel className="font-new-sans font-normal text-[#44403C] text-sm leading-[130%]">
                        Last Name
                      </FormLabel>
                      <FormControl>
                        <Input
                          placeholder="Enter your last name"
                          className="h-12 rounded-[4px] border-[#A8A29E] bg-[#F5F3EF] px-3 font-new-sans text-[#44403C] text-sm placeholder:text-[#A8A29E]"
                          {...field}
                        />
                      </FormControl>
                      <FormMessage />
                    </FormItem>
                  )}
                />
              </div>

              {/* Middle Name */}
              <FormField
                control={form.control}
                name="patronymic"
                render={({ field }) => (
                  <FormItem>
                    <FormLabel className="font-new-sans font-normal text-[#44403C] text-sm leading-[130%]">
                      Middle Name (optional)
                    </FormLabel>
                    <FormControl>
                      <Input
                        placeholder="Enter your patronymic"
                        className="h-12 rounded-[4px] border-[#A8A29E] bg-[#F5F3EF] px-3 font-new-sans text-[#44403C] text-sm placeholder:text-[#A8A29E]"
                        {...field}
                      />
                    </FormControl>
                    <FormMessage />
                  </FormItem>
                )}
              />

              {/* Phone Number */}
              <FormField
                control={form.control}
                name="phone"
                render={({ field }) => (
                  <FormItem>
                    <FormLabel className="font-new-sans font-normal text-[#44403C] text-sm leading-[130%]">
                      Phone Number
                    </FormLabel>
                    <FormControl>
                      <PhoneInput
                        defaultCountryAlpha2="AE"
                        placeholder="e.g. 50-123-4567"
                        {...field}
                      />
                    </FormControl>
                    <FormMessage />
                  </FormItem>
                )}
              />

              {/* Email */}
              <FormField
                control={form.control}
                name="email"
                render={({ field }) => (
                  <FormItem>
                    <FormLabel className="font-new-sans font-normal text-[#44403C] text-sm leading-[130%]">
                      Email
                    </FormLabel>
                    <FormControl>
                      <Input
                        placeholder="Enter your email"
                        type="email"
                        className="h-12 rounded-[4px] border-[#A8A29E] bg-[#F5F3EF] px-3 font-new-sans text-[#44403C] text-sm placeholder:text-[#A8A29E]"
                        {...field}
                      />
                    </FormControl>
                    <FormMessage />
                  </FormItem>
                )}
              />

              {/* UAE Residency Checkbox */}
              <FormField
                control={form.control}
                name="uaeResident"
                render={({ field }) => (
                  <FormItem>
                    <div className="flex items-center gap-2">
                      <Checkbox
                        id="uaeResident"
                        checked={field.value}
                        onCheckedChange={field.onChange}
                        className="data-[state=checked]:border-[#021171] data-[state=checked]:bg-[#021171]"
                      />
                      <FormLabel
                        htmlFor="uaeResident"
                        className="cursor-pointer font-new-sans font-normal text-[#44403C] text-sm leading-[150%] tracking-[-0.01em]"
                      >
                        I confirm I reside, or have an address in UAE
                      </FormLabel>
                    </div>
                    <FormMessage />
                  </FormItem>
                )}
              />
            </div>

            {/* OTP Notice */}
            <p className="font-new-sans text-[#44403C] text-sm leading-[150%] tracking-[-0.01em]">
              You will receive a <strong>one-time code</strong> to your email
              and phone to verify your profile.
            </p>

            {/* Continue Button */}
            <Button
              type="submit"
              disabled={isSubmitting}
              className="flex h-12 w-full items-center justify-center rounded-[4px] bg-[#021171] font-medium font-new-sans text-[#F5F3EF] text-base transition-opacity hover:opacity-90 disabled:cursor-not-allowed disabled:opacity-70"
            >
              {isSubmitting ? "Sending..." : "Continue"}
            </Button>

            {/* Login link */}
            <p className="text-center font-new-sans text-[#44403C] text-sm leading-[150%] tracking-[-0.01em]">
              Already have an account?{" "}
              <Link
                href={APP_ROUTES.AUTH.SIGN_IN}
                className="font-semibold text-[#44403C] hover:opacity-70"
              >
                Login
              </Link>
            </p>
          </form>
        </Form>
      </div>
    </div>
  );
}

