"use client";

import { zodResolver } from "@hookform/resolvers/zod";
import { signIn } from "next-auth/react";
import Link from "next/link";
import { useEffect, useState } from "react";
import { useForm } from "react-hook-form";
import { z } from "zod";

import { APP_ROUTES } from "@/shared/config/app-routes";
import { hardPush } from "@/shared/lib/routing/hard-push";
import { getIsClient } from "@/shared/lib/utils/get-is-client";
import { Form } from "@/shared/ui/form/form";
import { FormControl } from "@/shared/ui/form/form-control";
import { FormField } from "@/shared/ui/form/form-field";
import { FormItem } from "@/shared/ui/form/form-item";
import { FormLabel } from "@/shared/ui/form/form-label";
import { FormMessage } from "@/shared/ui/form/form-message";
import { Input } from "@/shared/ui/input";
import { toast } from "@/shared/ui/notification";
import { PasswordInput } from "@/shared/ui/password-input";

const loginSchema = z.object({
  email: z.string().email("Please enter a valid email"),
  password: z.string().min(1, "Password is required"),
});

type LoginFormData = z.infer<typeof loginSchema>;

function GoogleIcon() {
  return (
    <svg
      aria-hidden="true"
      width="20"
      height="20"
      viewBox="0 0 20 20"
      fill="none"
      xmlns="http://www.w3.org/2000/svg"
    >
      <path
        d="M19.6 10.23c0-.68-.06-1.36-.18-2H10v3.79h5.37a4.61 4.61 0 0 1-1.99 3.01v2.5h3.22c1.88-1.73 2.96-4.28 2.96-7.3z"
        fill="#4285F4"
      />
      <path
        d="M10 20c2.7 0 4.96-.9 6.61-2.43l-3.22-2.5c-.9.6-2.04.96-3.39.96-2.61 0-4.82-1.76-5.61-4.13H1.06v2.57A9.99 9.99 0 0 0 10 20z"
        fill="#34A853"
      />
      <path
        d="M4.39 11.9A5.9 5.9 0 0 1 4.08 10c0-.66.12-1.3.31-1.9V5.53H1.06A9.99 9.99 0 0 0 0 10c0 1.61.38 3.13 1.06 4.47l3.33-2.57z"
        fill="#FBBC05"
      />
      <path
        d="M10 3.97c1.47 0 2.8.51 3.84 1.5l2.87-2.87C15 .9 12.71 0 10 0A9.99 9.99 0 0 0 1.06 5.53L4.39 8.1C5.18 5.73 7.39 3.97 10 3.97z"
        fill="#EA4335"
      />
    </svg>
  );
}

function AppleIcon() {
  return (
    <svg
      aria-hidden="true"
      width="20"
      height="20"
      viewBox="0 0 814 1000"
      fill="none"
      xmlns="http://www.w3.org/2000/svg"
    >
      <path
        d="M788.1 340.9c-5.8 4.5-108.2 62.2-108.2 190.5 0 148.4 130.3 200.9 134.2 202.2-.6 3.2-20.7 71.9-68.7 141.9-42.8 61.6-87.5 123.1-155.5 123.1s-85.5-39.5-164-39.5c-76 0-103.7 40.8-165.9 40.8s-105.5-57.9-168.5-127.6C46.7 696 0 556.4 0 422.9c0-167.9 109.4-256.9 216.7-256.9 70.1 0 128.6 46.3 172.3 46.3 43.4 0 111.1-49 191.5-49 30.2 0 108.2 2.6 162.4 76.5zm-205.5-165.3c33.5-39.5 56.4-94.2 56.4-148.9 0-7.7-.6-15.5-1.9-22.5-53.5 2-116.8 35.7-154.3 80.1-30.5 35.7-58.5 90.4-58.5 145.8 0 8.4 1.3 16.7 1.9 19.3 3.2.6 8.4 1.3 13.6 1.3 48.1 0 109.5-32.3 143.8-75.1z"
        fill="#44403C"
      />
    </svg>
  );
}

function UaePassIcon() {
  return (
    <svg
      aria-hidden="true"
      width="21"
      height="20"
      viewBox="0 0 21 20"
      fill="none"
      xmlns="http://www.w3.org/2000/svg"
    >
      <rect x="0.5" width="20" height="20" rx="3" fill="#00AEEF" />
      <path
        d="M5.5 10h10M7.5 6.5h6M7.5 13.5h6"
        stroke="white"
        strokeWidth="1.5"
        strokeLinecap="round"
      />
    </svg>
  );
}

const SOCIAL_BUTTONS = [
  { key: "google", Icon: GoogleIcon, label: "Google" },
  { key: "apple", Icon: AppleIcon, label: "Apple" },
  { key: "uaepass", Icon: UaePassIcon, label: "UAE Pass" },
];

export default function SignInPage() {
  const [isLoading, setIsLoading] = useState(false);
  const [callbackUrl, setCallbackUrl] = useState<string | null>(null);

  useEffect(() => {
    if (!getIsClient()) return;
    const params = new URLSearchParams(window.location.search);
    setCallbackUrl(params.get("callbackUrl"));
  }, []);

  const form = useForm<LoginFormData>({
    resolver: zodResolver(loginSchema),
    defaultValues: { email: "", password: "" },
  });

  const onSubmit = async (data: LoginFormData) => {
    setIsLoading(true);
    try {
      const result = await signIn("credentials", {
        email: data.email,
        password: data.password,
        redirect: false,
      });

      if (result?.error) {
        toast.error("Sign In Failed", {
          description: "Invalid email or password",
        });
        return;
      }

      if (result?.ok) {
        hardPush(callbackUrl || APP_ROUTES.PROFILE);
      }
    } catch {
      toast.error("Sign In Failed", {
        description: "An unexpected error occurred",
      });
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="flex w-full flex-col gap-8">
      {/* Header */}
      <div className="flex flex-col">
        <h1 className="font-light font-new-serif text-2xl text-[#44403C] leading-[120%]">
          Welcome Back
        </h1>
        <p className="font-new-sans text-[#44403C] text-base leading-[150%] tracking-[-0.01em]">
          Login to your account to access LuxFlow
        </p>
      </div>

      {/* Social Buttons */}
      <div className="flex gap-2">
        {SOCIAL_BUTTONS.map(({ key, Icon, label }) => (
          <button
            key={key}
            type="button"
            disabled
            className="flex flex-1 cursor-not-allowed items-center justify-center gap-2 rounded-[4px] border border-[#A8A29E] bg-[#F5F3EF] px-4 py-3 font-medium font-new-sans text-[#44403C] text-sm tracking-[-0.01em] opacity-70"
          >
            <Icon />
            <span>{label}</span>
          </button>
        ))}
      </div>

      {/* Form Section */}
      <div className="flex flex-col gap-5">
        {/* OR Divider */}
        <div className="flex items-center gap-4">
          <div className="flex-1 border-[#D6D3D1] border-t" />
          <span className="font-bold font-new-sans text-[#A8A29E] text-sm tracking-[-0.01em]">
            OR
          </span>
          <div className="flex-1 border-[#D6D3D1] border-t" />
        </div>

        <Form {...form}>
          <form
            onSubmit={form.handleSubmit(onSubmit)}
            className="flex flex-col gap-5"
          >
            <div className="flex flex-col gap-2">
              {/* Email */}
              <FormField
                control={form.control}
                name="email"
                render={({ field }) => (
                  <FormItem>
                    <FormLabel className="font-new-sans font-normal text-[#44403C] text-sm leading-[130%]">
                      Email
                    </FormLabel>
                    <FormControl>
                      <Input
                        placeholder="Enter your email"
                        type="email"
                        className="h-12 rounded-[4px] border-[#A8A29E] bg-[#F5F3EF] px-3 font-new-sans text-[#44403C] text-sm placeholder:text-[#A8A29E]"
                        {...field}
                      />
                    </FormControl>
                    <FormMessage />
                  </FormItem>
                )}
              />

              {/* Password */}
              <FormField
                control={form.control}
                name="password"
                render={({ field }) => (
                  <FormItem>
                    <FormLabel className="font-new-sans font-normal text-[#44403C] text-sm leading-[130%]">
                      Password
                    </FormLabel>
                    <FormControl>
                      <PasswordInput
                        placeholder="Placeholder"
                        containerClassName="h-12 rounded-[4px] border-[#A8A29E] bg-[#F5F3EF] px-3"
                        className="font-new-sans text-[#44403C] text-sm placeholder:text-[#A8A29E]"
                        {...field}
                      />
                    </FormControl>
                    <div className="flex justify-end">
                      <Link
                        href={APP_ROUTES.AUTH.REQUEST_FORGOT_PASSWORD}
                        className="font-new-sans text-[#000944] text-xs leading-[130%] transition-opacity hover:opacity-70"
                      >
                        Forgot Password
                      </Link>
                    </div>
                    <FormMessage />
                  </FormItem>
                )}
              />
            </div>

            {/* Login Button */}
            <button
              type="submit"
              disabled={isLoading}
              className="flex h-12 w-full items-center justify-center rounded-[4px] bg-[#021171] font-medium font-new-sans text-[#F5F3EF] text-base transition-opacity hover:opacity-90 disabled:cursor-not-allowed disabled:opacity-70"
            >
              {isLoading ? "Signing In..." : "Login"}
            </button>

            {/* Sign up link */}
            <p className="text-center font-new-sans text-[#44403C] text-sm leading-[150%] tracking-[-0.01em]">
              New to LuxFlow.{" "}
              <Link
                href={APP_ROUTES.AUTH.REGISTER}
                className="font-semibold text-[#44403C] hover:opacity-70"
              >
                Create an Account
              </Link>
            </p>
          </form>
        </Form>
      </div>
    </div>
  );
}

/** @type {import('tailwindcss').Config} */
module.exports = {
  darkMode: ["class"],
  content: [
    "./pages/**/*.{ts,tsx}",
    "./components/**/*.{ts,tsx}",
    "./app/**/*.{ts,tsx}",
    "./src/**/*.{ts,tsx}",
  ],
  theme: {
    // screens: {
    //   "375": "375px",
    //   "540": "540px",
    //   "768": "768px",
    //   "1024": "1024px",
    //   "1200": "1200px",
    //   "1600": "1600px",
    //   "1920": "1920px",
    //   "2560": "2560px",
    // },

    container: {
      center: true,
      screens: {
        "2xl": "1240px",
      },
    },

    extend: {
      fontFamily: {
        sans: ["var(--font-sans)", "sans-serif"],
        serif: ["var(--font-serif)", "serif"],
        roboto: ["var(--font-roboto)", "sans-serif"],

        // REDESIGN: NEW FONTS
        "new-sans": ["var(--font-dm-sans)", "sans-serif"],
        "new-serif": ["var(--font-feature-serif)", "serif"],
      },
      spacing: {
        "input-100": "0.5625rem",
        "input-200": "0.9375rem",
        "btn-100": "0.375rem",
        "btn-200": "1rem",
        "btn-300": "0.5rem",
        "btn-400": "1.5rem",
        "btn-500": "0.6875rem",
        "btn-600": "3.625rem",
        "btn-700": "3.125rem",
        container: "0.625rem",
        "gap-default": "0.9375rem",
      },
      borderRadius: {
        input: "0.625rem",
        button: "0.75rem",
        container: "1.25rem",
        /* new radius for Shadcn */
        lg: "var(--radius)",
        md: "calc(var(--radius) - 2px)",
        sm: "calc(var(--radius) - 4px)",
      },
      colors: {
        border: "hsl(var(--border))",
        input: "hsl(var(--input))",
        ring: "hsl(var(--ring))",
        background: "hsl(var(--background))",
        foreground: "hsl(var(--foreground))",

        primary: {
          DEFAULT: "hsl(var(--primary))",
          foreground: "hsl(var(--primary-foreground))",
          active: "hsl(var(--primary-active))",
        },
        secondary: {
          DEFAULT: "hsl(var(--secondary))",
          foreground: "hsl(var(--secondary-foreground))",
        },
        destructive: {
          DEFAULT: "hsl(var(--destructive))",
          foreground: "hsl(var(--destructive-foreground))",
          active: "hsl(var(--destructive-active))",
        },
        muted: {
          DEFAULT: "hsl(var(--muted))",
          foreground: "hsl(var(--muted-foreground))",
        },
        accent: {
          DEFAULT: "hsl(var(--accent))",
          foreground: "hsl(var(--accent-foreground))",
          active: "hsl(var(--accent-active))",
        },
        popover: {
