import { Lock, Sparkles, ShieldCheck } from "lucide-react";
import type { FC, ReactNode } from "react";

import { cn } from "@/shared/lib/ui/cn";
import { Header } from "@/widgets/header";

type Feature = {
  label: string;
} & ({ Icon: React.ComponentType<{ className?: string; size?: number; strokeWidth?: number }> } | { imgSrc: string });

const FEATURES: Feature[] = [
  { imgSrc: "/new-design-images/auth/discreet-icon.svg", label: "100% Discreet Transactions" },
  { Icon: Sparkles, label: "AI-Powered Valuation" },
  { Icon: ShieldCheck, label: "Fully-Insured Shipping" },
  { Icon: Lock, label: "Secure Storage" },
];

type AuthLayoutProps = {
  children: ReactNode;
};

export const AuthLayout: FC<AuthLayoutProps> = ({ children }) => (
  <div className="new-design mt-[61px] flex flex-col bg-[#F5F3EF] max-lg:mt-[48px] lg:h-[calc(100svh-61px)] lg:overflow-hidden">
    <Header />

    <div className="relative flex flex-1 items-stretch lg:min-h-0">
      {/* Wave background */}
      <img
        src="/new-design-images/testimonial-wave.webp"
        alt=""
        aria-hidden
        className="pointer-events-none absolute inset-0 size-full object-cover opacity-60"
      />

      {/* Left: Marketing Content */}
      <div className="relative hidden min-h-0 flex-1 flex-col justify-between p-10 lg:flex">
        {/* UAE Badge */}
        <div className="flex w-fit items-center gap-3 rounded-full border border-[#A8A29E] px-4 py-3">
          <span aria-hidden>🇦🇪</span>
          <span className="font-new-sans text-[#44403C] text-base leading-[150%] tracking-[-0.01em]">
            Now available in UAE
          </span>
        </div>

        {/* Hero Headline */}
        <p
          className="max-w-[700px] font-new-serif text-[#000944] text-[72px] leading-[110%]"
          style={{ fontWeight: 200 }}
        >
          Your{" "}
          <span className="text-[#001a8c]">secured platform</span>
          {" "}for selling and buyback luxury items.
        </p>

        {/* Feature Callouts */}
        <div className="flex max-w-[660px] flex-wrap gap-x-10">
          {FEATURES.map((feature, i) => (
            <div
              className={cn(
                "flex w-[299px] items-center gap-2 py-5",
                i < 2 && "border-[#D6D3D1] border-b"
              )}
              key={feature.label}
            >
              {"imgSrc" in feature ? (
                <img
                  src={feature.imgSrc}
                  alt=""
                  className="shrink-0"
                  width={32}
                  height={32}
                />
              ) : (
                <feature.Icon
                  className="shrink-0 text-[#44403C]"
                  size={32}
                  strokeWidth={1.25}
                />
              )}
              <span className="font-new-sans text-[#44403C] text-base leading-[150%] tracking-[-0.01em]">
                {feature.label}
              </span>
            </div>
          ))}
        </div>
      </div>

      {/* Right: Form Card */}
      <div className="relative flex w-full items-center justify-center px-6 py-8 lg:w-[660px] lg:shrink-0 lg:px-[120px]">
        <div className="w-full max-w-[420px] rounded-2xl border border-[#D6D3D1] bg-[#F5F3EF] pt-8 pb-6 shadow-[0px_20px_28px_rgba(0,0,0,0.05)] [padding-inline:24px]">
          {children}
        </div>
      </div>

      {/* Bottom-right seal */}
      <div className="pointer-events-none absolute bottom-[-76px] right-[-65px] flex h-[263px] w-[259px] items-center justify-center">
        <div className="-rotate-[14.89deg] flex-none">
          <img
            src="/new-design-images/auth/seal.png"
            alt=""
            className="h-[216px] w-[210px] object-cover shadow-[0px_4px_12px_0px_rgba(0,0,0,0.35)]"
          />
        </div>
      </div>
    </div>
  </div>
);

